// Cross-subscription resource move via Bicep re-deployment
// (ARM does not support true cross-sub move for all types;
//  for IaaS it's often safer to redeploy)

// 1. Export current config
// az group export --name myapp-old-rg > exported.json

// 2. Target subscription scope deployment
targetScope = 'subscription'

param location string = 'eastus2'

resource newRg 'Microsoft.Resources/resourceGroups@2022-09-01' = {
  name: 'myapp-new-rg'
  location: location
}

module vm 'vm.bicep' = {
  name: 'vm-redeploy'
  scope: newRg
  params: {
    // parameters from the exported JSON
    vmName: 'myvm'
    vmSize: 'Standard_D2s_v5'
    location: location
  }
}

import subprocess, json

def check_broken_references(resource_group):
    """After a move, find resources whose dependency IDs point to the old RG."""
    result = subprocess.run(
        ['az', 'resource', 'list', '--resource-group', resource_group, '-o', 'json'],
        capture_output=True, text=True
    )
    resources = json.loads(result.stdout)
    old_rg = 'myapp-old-rg'
    broken = []
    for r in resources:
        deps = json.dumps(r.get('properties', {}))
        if old_rg.lower() in deps.lower():
            broken.append({'name': r['name'], 'type': r['type']})
    return broken

broken = check_broken_references('myapp-new-rg')
if broken:
    print('Resources with possible stale references to old RG:')
    for b in broken:
        print(f"  {b['type']}: {b['name']}")
else:
    print('No stale references detected')
